const COMPARISON_EX1 = [
{id:1,type:'fill',q:`I think spring is __________ season of the year.`,vi:`Tôi nghĩ mùa xuân là mùa đẹp nhất trong năm.`,opts:["A. beautiful","B. very beautiful","C. more beautiful","D. the most beautiful"],ans:3,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: D. the most beautiful</div><div class="ex-card mb-2">I think spring is the most beautiful season of the year.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Cụm "...season of the year" ngụ ý đang so sánh mùa xuân với TẤT CẢ các mùa còn lại trong năm → dùng so sánh nhất. "Beautiful" là tính từ dài (3 âm tiết) → "the most beautiful".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — tính từ nguyên thể, không thể hiện ý so sánh, sai vì thiếu "the most".<br>B — "very beautiful" chỉ là cụm nhấn mạnh, không phải cấu trúc so sánh nhất cần thiết ở đây.<br>C — "more beautiful" là so sánh hơn, cần "than" đi kèm để so sánh 2 đối tượng, không phù hợp với "of the year" (so sánh với cả tập hợp).</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>season</i> /ˈsiːzn/ (n): mùa; <i>beautiful</i> /ˈbjuːtɪfl/ (adj): đẹp.</div>`},

{id:2,type:'fill',q:`The larger the apartment is, the __________ its price is.`,vi:`Căn hộ càng rộng thì giá của nó càng đắt.`,opts:["A. expensive","B. more expensive","C. expensively","D. most expensive"],ans:1,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: B. more expensive</div><div class="ex-card mb-2">The larger the apartment is, the more expensive its price is.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Đây là cấu trúc so sánh đồng tiến "The + so sánh hơn, the + so sánh hơn" (càng...thì càng). "Expensive" là tính từ dài → "the more expensive".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — thiếu "the" và dạng so sánh, không đúng cấu trúc đồng tiến.<br>C — "expensively" là trạng từ, không bổ nghĩa cho danh từ "price" (cần tính từ sau "is").<br>D — "most expensive" là so sánh nhất, sai cấu trúc vì cần dạng so sánh hơn "more".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>apartment</i> /əˈpɑːrtmənt/ (n): căn hộ; <i>expensive</i> /ɪkˈspensɪv/ (adj): đắt đỏ.</div>`},

{id:3,type:'fill',q:`The faster we walk, __________ we will get there.`,vi:`Chúng ta đi bộ càng nhanh thì càng sớm đến nơi.`,opts:["A. the soonest","B. the soon","C. the more soon","D. the sooner"],ans:3,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: D. the sooner</div><div class="ex-card mb-2">The faster we walk, the sooner we will get there.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Cấu trúc đồng tiến "The + so sánh hơn, the + so sánh hơn". "Soon" là trạng từ ngắn → dạng so sánh hơn là "sooner", thêm "the" phía trước.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — "the soonest" là so sánh nhất, sai vì cấu trúc này cần so sánh hơn.<br>B — "the soon" không phải dạng so sánh, thiếu đuôi -er.<br>C — "soon" là từ ngắn nên không dùng "more" để so sánh hơn.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>soon</i> /suːn/ (adv): sớm; <i>get there</i>: đến nơi đó.</div>`},

{id:4,type:'fill',q:`"Why did you buy these oranges?" "They were __________ I could find."`,vi:`"Sao bạn lại mua những quả cam này?" "Đó là những quả rẻ nhất tôi có thể tìm được."`,opts:["A. cheapest","B. cheapest ones","C. the cheapest ones","D. the most cheapest"],ans:2,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: C. the cheapest ones</div><div class="ex-card mb-2">They were the cheapest ones I could find.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> So sánh nhất luôn cần mạo từ "the" đứng trước. "Ones" thay thế cho "oranges" để tránh lặp từ. "Cheap" là tính từ ngắn → thêm "-est": cheapest.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — thiếu "the" và danh từ thay thế "ones".<br>B — thiếu mạo từ "the" bắt buộc trước so sánh nhất.<br>D — "cheap" là tính từ ngắn, không dùng "most" (sai vì kết hợp cả "most" và "-est" là thừa/sai ngữ pháp).</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>cheap</i> /tʃiːp/ (adj): rẻ; <i>ones</i>: đại từ thay thế danh từ đếm được đã nhắc tới.</div>`},

{id:5,type:'fill',q:`__________ you drive, the more likely you are to have an accident.`,vi:`Bạn lái xe càng nhanh thì càng dễ gặp tai nạn.`,opts:["A. Fastest","B. The fastest","C. Faster","D. The faster"],ans:3,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: D. The faster</div><div class="ex-card mb-2">The faster you drive, the more likely you are to have an accident.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Cấu trúc đồng tiến bắt đầu câu bằng "The + so sánh hơn". "Fast" là trạng từ ngắn → "the faster", tương ứng với vế sau "the more likely".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A, C — thiếu "the" bắt buộc ở đầu mỗi vế trong cấu trúc đồng tiến.<br>B — "the fastest" là so sánh nhất, sai vì cần so sánh hơn để khớp với vế "the more likely" phía sau.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>accident</i> /ˈæksɪdənt/ (n): tai nạn; <i>likely</i> /ˈlaɪkli/ (adj): có khả năng.</div>`},

{id:6,type:'fill',q:`The more he learns, __________ he becomes.`,vi:`Anh ấy học càng nhiều thì càng trở nên thông minh.`,opts:["A. smarter","B. the smarter","C. smartest","D. the smartest"],ans:1,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: B. the smarter</div><div class="ex-card mb-2">The more he learns, the smarter he becomes.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Vế đầu đã có "The more he learns" (so sánh đồng tiến) → vế sau phải giữ cấu trúc song song "the + so sánh hơn". "Smart" là tính từ ngắn → "the smarter".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — thiếu "the" bắt buộc để khớp cấu trúc đồng tiến.<br>C, D — "smartest" là so sánh nhất, sai vì cấu trúc "the more..., the + so sánh hơn" cần dạng so sánh hơn, không phải so sánh nhất.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>smart</i> /smɑːrt/ (adj): thông minh; <i>become</i> /bɪˈkʌm/ (v): trở nên.</div>`},

{id:7,type:'fill',q:`__________ you study, the more you will learn.`,vi:`Bạn học càng chăm thì càng học được nhiều.`,opts:["A. The harder","B. Harder","C. The hardest","D. Hardest"],ans:0,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: A. The harder</div><div class="ex-card mb-2">The harder you study, the more you will learn.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Đầu câu là vế đầu của cấu trúc đồng tiến, bắt buộc có "The + so sánh hơn". "Hard" là trạng từ ngắn → "the harder", song song với "the more" ở vế sau.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>B — thiếu "the" bắt buộc ở đầu vế trong cấu trúc đồng tiến.<br>C, D — dạng so sánh nhất, sai vì cấu trúc này chỉ dùng so sánh hơn.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>hard</i> /hɑːrd/ (adv): chăm chỉ, cật lực; <i>study</i> /ˈstʌdi/ (v): học.</div>`},

{id:8,type:'fill',q:`The older he got, __________ he became.`,vi:`Ông ấy càng già thì càng trở nên trầm tính.`,opts:["A. quieter","B. the quieter","C. quietest","D. the quietest"],ans:1,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: B. the quieter</div><div class="ex-card mb-2">The older he got, the quieter he became.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Vế đầu "The older he got" là so sánh đồng tiến → vế sau cũng phải là "the + so sánh hơn". "Quiet" tận cùng đuôi -et (1 trong 5 đuôi tính từ ngắn) → "quieter".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — thiếu "the" cần thiết để khớp cấu trúc.<br>C, D — "quietest" là so sánh nhất, không phù hợp với cấu trúc đồng tiến cần so sánh hơn.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>quiet</i> /ˈkwaɪət/ (adj): yên tĩnh, trầm tính; <i>get old</i>: già đi.</div>`},

{id:9,type:'fill',q:`Phil is __________ person we have ever known.`,vi:`Phil là người hạnh phúc nhất mà chúng tôi từng biết.`,opts:["A. the happier","B. the happiest","C. happier","D. happiest"],ans:1,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: B. the happiest</div><div class="ex-card mb-2">Phil is the happiest person we have ever known.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Cụm "...person we have ever known" (mệnh đề quan hệ rút gọn với "have/has ever + P2") là dấu hiệu điển hình của so sánh nhất. "Happy" tận cùng phụ âm+y → đổi y thành i, thêm -est: happiest, kèm "the".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — "the happier" là so sánh hơn, sai vì không có "than" và có dấu hiệu "ever" chỉ so sánh nhất.<br>C, D — thiếu mạo từ "the" bắt buộc trước so sánh nhất.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>happy</i> /ˈhæpi/ (adj): hạnh phúc; cấu trúc "the + so sánh nhất + N + S + have/has ever + P2".</div>`},

{id:10,type:'fill',q:`Which woman are you going to vote for? – I'm not sure. Everyone says that Joan is __________.`,vi:`Bạn sẽ bầu cho người phụ nữ nào? – Tôi không chắc. Mọi người đều nói rằng Joan thông minh hơn (trong hai người).`,opts:["A. smarter","B. the smarter","C. more smarter","D. more smart"],ans:1,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: B. the smarter</div><div class="ex-card mb-2">Everyone says that Joan is the smarter (of the two).</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Khi so sánh hơn giữa đúng HAI đối tượng đã được xác định rõ trong ngữ cảnh (2 nữ ứng viên), tiếng Anh dùng "the + so sánh hơn" thay vì so sánh hơn thông thường, vì lúc này "the smarter" mang nghĩa như "người thông minh hơn (trong 2 người)".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — thiếu "the", không diễn tả đúng sắc thái "người hơn trong 2 người" theo ngữ cảnh.<br>C — sai vì "smart" là tính từ ngắn, không dùng "more" kèm "-er" (lỗi so sánh kép).<br>D — "more smart" sai vì "smart" là tính từ ngắn, phải dùng "-er" chứ không dùng "more".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>vote for</i>: bỏ phiếu cho; <i>smart</i> /smɑːrt/ (adj): thông minh, lanh lợi.</div>`},

{id:11,type:'fill',q:`I thought this test would be difficult, but it is __________ test I've ever taken.`,vi:`Tôi từng nghĩ bài kiểm tra này sẽ khó, nhưng nó là bài dễ nhất mà tôi từng làm.`,opts:["A. the easiest","B. easier","C. the most easy","D. easily"],ans:0,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: A. the easiest</div><div class="ex-card mb-2">It is the easiest test I've ever taken.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Cụm "...I've ever taken" là dấu hiệu so sánh nhất. "Easy" tận cùng phụ âm+y → đổi y thành i, thêm -est: easiest, kèm "the".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>B — "easier" là so sánh hơn, không phù hợp với dấu hiệu "ever" (cần so sánh nhất).<br>C — "easy" là tính từ ngắn (2 âm tiết, đuôi -y) nên không dùng "the most", phải dùng "-est".<br>D — "easily" là trạng từ, không thể đứng trước danh từ "test" để bổ nghĩa cho nó.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>easy</i> /ˈiːzi/ (adj): dễ; <i>take a test</i>: làm bài kiểm tra.</div>`},

{id:12,type:'fill',q:`It's too noisy here. Can we go somewhere __________?`,vi:`Ở đây ồn quá. Chúng ta có thể đến chỗ nào yên tĩnh hơn không?`,opts:["A. noisier","B. more quiet","C. more noisy","D. quieter"],ans:3,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: D. quieter</div><div class="ex-card mb-2">Can we go somewhere quieter?</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Ngữ cảnh "too noisy" (quá ồn) → cần một nơi YÊN TĨNH HƠN, nên phải dùng tính từ "quiet" ở dạng so sánh hơn, không phải "noisy". "Quiet" tận cùng đuôi -et (tính từ ngắn) → thêm "-er": quieter.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — "noisier" (ồn hơn) trái ngược hoàn toàn với ý muốn của câu (muốn nơi yên tĩnh hơn).<br>B — "quiet" là tính từ ngắn, phải dùng "-er", không dùng "more".<br>C — "noisy" sai nghĩa như đáp án A, và cũng sai vì đã có "more" (không cần vì noisy vẫn là tính từ ngắn — dù đây chủ yếu sai về nghĩa).</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>noisy</i> /ˈnɔɪzi/ (adj): ồn ào; <i>quiet</i> /ˈkwaɪət/ (adj): yên tĩnh.</div>`},

{id:13,type:'fill',q:`__________ the time passes, __________ I feel! The deadline of my thesis is coming, but I have just finished half of it.`,vi:`Thời gian trôi càng nhanh, tôi càng cảm thấy lo lắng! Hạn nộp luận văn sắp đến, nhưng tôi mới hoàn thành được một nửa.`,opts:["A. The faster/the nervous","B. The more fast/the nervous","C. The fast/the more nervous","D. The faster/the more nervous"],ans:3,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: D. The faster/the more nervous</div><div class="ex-card mb-2">The faster the time passes, the more nervous I feel!</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Cả 2 vế đều cần cấu trúc "the + so sánh hơn". "Fast" là trạng từ ngắn → "the faster"; "nervous" là tính từ dài (2 âm tiết, không thuộc 5 đuôi đặc biệt) → "the more nervous".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — thiếu "the" trước "nervous", sai cấu trúc song song.<br>B — "fast" là từ ngắn, không dùng "more fast" mà phải dùng "faster".<br>C — thiếu "-er" ở vế đầu ("the fast" sai, phải là "the faster").</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>nervous</i> /ˈnɜːrvəs/ (adj): lo lắng; <i>thesis</i> /ˈθiːsɪs/ (n): luận văn; <i>deadline</i>: hạn chót.</div>`},

{id:14,type:'fill',q:`China is the country with __________ population.`,vi:`Trung Quốc là quốc gia có dân số đông nhất.`,opts:["A. the larger","B. the more large","C. the largest","D. the most large"],ans:2,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: C. the largest</div><div class="ex-card mb-2">China is the country with the largest population.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> So sánh Trung Quốc với tất cả các quốc gia khác trên thế giới về dân số → dùng so sánh nhất. "Large" tận cùng -e → chỉ thêm "-st": largest.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — "the larger" là so sánh hơn, sai vì đây là so sánh với cả một tập hợp (tất cả các nước), cần so sánh nhất.<br>B — sai vì "large" là tính từ ngắn (1 âm tiết), không dùng "more".<br>D — cùng lỗi với B, "large" không dùng "the most" mà phải dùng "-est".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>population</i> /ˌpɒpjuˈleɪʃn/ (n): dân số; <i>large</i> /lɑːrdʒ/ (adj): lớn, rộng.</div>`},

{id:15,type:'fill',q:`She sat there quietly, but during all that time she was getting __________. Finally she exploded.`,vi:`Cô ấy ngồi đó im lặng, nhưng trong suốt thời gian đó cô ấy càng lúc càng tức giận. Cuối cùng cô ấy đã bùng nổ.`,opts:["A. more and more angrily","B. the more angry","C. angrier and angrier","D. the most angry"],ans:2,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: C. angrier and angrier</div><div class="ex-card mb-2">She was getting angrier and angrier.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Đây là so sánh lũy tiến (càng ngày càng) với động từ "get/become" — diễn tả mức độ tăng dần theo thời gian. "Angry" tận cùng phụ âm+y (tính từ ngắn) → đổi y thành i, thêm -er, lặp lại 2 lần nối bằng "and": angrier and angrier.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — "angrily" là trạng từ, không phù hợp vì "angry" ở đây bổ nghĩa cho chủ ngữ "she" (cần tính từ sau "get/become").<br>B, D — không đúng cấu trúc so sánh lũy tiến (cần lặp lại dạng so sánh hơn nối bằng "and", không dùng "the").</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>angry</i> /ˈæŋɡri/ (adj): tức giận; <i>explode</i> /ɪkˈsploʊd/ (v): bùng nổ, nổi giận.</div>`},

{id:16,type:'fill',q:`Her grandfather's illness was __________ we thought at first.`,vi:`Bệnh của ông cô ấy nghiêm trọng hơn những gì chúng tôi nghĩ lúc đầu.`,opts:["A. more seriously as","B. as seriously as","C. more serious than","D. as serious than"],ans:2,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: C. more serious than</div><div class="ex-card mb-2">Her grandfather's illness was more serious than we thought at first.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Câu diễn tả mức độ nghiêm trọng THỰC TẾ vượt quá dự đoán ban đầu → dùng so sánh hơn "more...than". "Serious" là tính từ dài → "more serious"; sau tính từ đứng sau "was" cần tính từ (không phải trạng từ), vì bổ nghĩa cho "illness".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — "seriously" là trạng từ, sai vì cần tính từ sau động từ "was" (linking verb); ngoài ra dùng "as" thay vì "than" là sai cấu trúc so sánh hơn.<br>B — "as seriously as" là so sánh bằng, sai nghĩa (câu này so sánh HƠN chứ không phải bằng) và sai từ loại (seriously - trạng từ).<br>D — "as serious than" sai cấu trúc, "as" phải đi với "as" (so sánh bằng), không được kết hợp với "than".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>illness</i> /ˈɪlnəs/ (n): bệnh tật; <i>serious</i> /ˈsɪəriəs/ (adj): nghiêm trọng.</div>`},

{id:17,type:'fill',q:`My brother was feeling tired last night, so he went to bed __________ usual.`,vi:`Tối qua anh trai tôi cảm thấy mệt nên anh ấy đã đi ngủ sớm hơn bình thường.`,opts:["A. more early than","B. as early as","C. more earlier as","D. earlier than"],ans:3,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: D. earlier than</div><div class="ex-card mb-2">He went to bed earlier than usual.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Vì mệt nên đi ngủ SỚM HƠN bình thường → so sánh hơn. "Early" là trạng từ ngắn (tận cùng -y) → đổi y thành i, thêm -er: earlier, đi với "than".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — "early" là từ ngắn, không dùng "more" mà phải dùng "-er".<br>B — "as early as" là so sánh bằng, sai nghĩa (câu cần so sánh hơn vì mệt nên đi ngủ sớm HƠN).<br>C — "more earlier" là lỗi so sánh kép (dùng cả "more" và "-er"), và "as" sai phải là "than".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>tired</i> /ˈtaɪərd/ (adj): mệt mỏi; <i>early</i> /ˈɜːrli/ (adv): sớm; <i>usual</i>: bình thường, thường lệ.</div>`},

{id:18,type:'fill',q:`__________ you study for these exams, __________ you will do.`,vi:`Bạn học cho những kỳ thi này càng chăm chỉ thì bạn sẽ làm bài càng tốt.`,opts:["A. The harder/the better","B. The more/the much","C. The hardest/the best","D. The more hard/the more good"],ans:0,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: A. The harder/the better</div><div class="ex-card mb-2">The harder you study for these exams, the better you will do.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Cấu trúc đồng tiến "The + so sánh hơn, the + so sánh hơn". "Hard" (trạng từ ngắn) → "harder"; "well" có dạng so sánh hơn bất quy tắc là "better".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>B — "the much" không phải dạng so sánh hợp lệ, "much" phải chia thành "more" khi ở dạng nguyên thể, không dùng trực tiếp ở đây.<br>C — "hardest/best" là so sánh nhất, sai vì cấu trúc đồng tiến cần so sánh hơn.<br>D — "more hard" và "more good" đều sai vì "hard" là từ ngắn (dùng -er) và "good" là bất quy tắc (dùng "better", không phải "more good").</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>exam</i> /ɪɡˈzæm/ (n): kỳ thi; <i>do well</i>: làm tốt.</div>`},

{id:19,type:'fill',q:`That is his house which is __________ mine.`,vi:`Đó là nhà của anh ấy, to gấp đôi nhà tôi.`,opts:["A. twice as big as","B. as twice big as","C. as two times big as","D. as big as twice"],ans:0,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: A. twice as big as</div><div class="ex-card mb-2">That is his house which is twice as big as mine.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Cấu trúc so sánh gấp nhiều lần: S + V + <b>multiple number</b> (twice/half/3 times...) + as + adj + as + N/pronoun. "Twice" (số nhân) đứng TRƯỚC "as...as".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>B, D — sai vị trí của "twice", phải đặt "twice" trước "as", không đặt xen giữa hoặc sau.<br>C — "as two times big as" sai cấu trúc, phải dùng "twice" (không dùng "two times" theo cấu trúc chuẩn với "as...as") và cũng sai vị trí.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>twice</i> /twaɪs/ (adv): gấp đôi; <i>big</i> /bɪɡ/ (adj): to, lớn.</div>`},

{id:20,type:'fill',q:`My town is __________ this city.`,vi:`Thị trấn của tôi thanh bình hơn thành phố này.`,opts:["A. more peaceful","B. more peacefully than","C. peaceful than","D. more peaceful than"],ans:3,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: D. more peaceful than</div><div class="ex-card mb-2">My town is more peaceful than this city.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Cấu trúc so sánh hơn với tính từ dài: S + V + more + adj + than + S2. "Peaceful" là tính từ dài (2 âm tiết, không thuộc 5 đuôi ngắn) → "more peaceful than".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — thiếu "than" để hoàn chỉnh cấu trúc so sánh hơn.<br>B — "peacefully" là trạng từ, sai vì cần tính từ sau động từ "is" bổ nghĩa cho "town".<br>C — thiếu từ "more" cần thiết vì "peaceful" là tính từ dài, không thể chỉ thêm "than" mà không có "more".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>peaceful</i> /ˈpiːsfl/ (adj): thanh bình, yên bình; <i>town</i>: thị trấn.</div>`},

{id:21,type:'fill',q:`I was ill yesterday but I am __________ today.`,vi:`Hôm qua tôi bị ốm nhưng hôm nay tôi khỏe hơn rồi.`,opts:["A. better","B. gooder","C. weller","D. best"],ans:0,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: A. better</div><div class="ex-card mb-2">I am better today.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> So sánh sức khỏe hôm nay với hôm qua (bị ốm) → dùng so sánh hơn của "good/well" là dạng bất quy tắc "better".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>B, C — "gooder" và "weller" không tồn tại trong tiếng Anh, vì "good/well" là tính từ/trạng từ bất quy tắc, không thêm "-er" thông thường.<br>D — "best" là so sánh nhất, sai vì câu chỉ so sánh giữa 2 thời điểm (hôm qua và hôm nay), cần so sánh hơn.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>ill</i> /ɪl/ (adj): ốm, bệnh; <i>better</i> /ˈbetər/: khá hơn, khỏe hơn (so sánh hơn của good/well).</div>`},

{id:22,type:'fill',q:`Monkeys are __________ learners than elephants.`,vi:`Khỉ học nhanh hơn voi.`,opts:["A. faster","B. very fast","C. more faster","D. more fast"],ans:0,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: A. faster</div><div class="ex-card mb-2">Monkeys are faster learners than elephants.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> "Fast" là tính từ ngắn (1 âm tiết) bổ nghĩa cho danh từ "learners" → chỉ cần thêm "-er": faster, kèm "than" phía sau để so sánh.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>B — "very fast" không phải cấu trúc so sánh, thiếu "than" và không thể hiện ý so sánh hơn.<br>C — "more faster" là lỗi so sánh kép (dùng cả "more" và "-er" cùng lúc), sai ngữ pháp.<br>D — "more fast" sai vì "fast" là tính từ ngắn, phải dùng "-er" chứ không dùng "more".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>learner</i> /ˈlɜːrnər/ (n): người học; <i>fast</i> /fæst/ (adj): nhanh.</div>`},

{id:23,type:'fill',q:`The use of detail is __________ method of developing a controlling idea and almost all students employ this method.`,vi:`Việc sử dụng chi tiết là phương pháp phổ biến nhất để phát triển ý chính, và hầu hết học sinh đều dùng phương pháp này.`,opts:["A. more common","B. common","C. most common","D. the most common"],ans:3,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: D. the most common</div><div class="ex-card mb-2">The use of detail is the most common method of developing a controlling idea.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Vế sau "almost all students employ this method" khẳng định đây là phương pháp phổ biến NHẤT trong tất cả các phương pháp → cần so sánh nhất. "Common" là tính từ dài (2 âm tiết, không thuộc 5 đuôi ngắn) → "the most common", có "the" vì đi kèm danh từ "method".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — "more common" là so sánh hơn, thiếu "than" và không khớp với ý nghĩa "phổ biến nhất" trong ngữ cảnh.<br>B — tính từ nguyên thể, không mang nghĩa so sánh nhất mà câu yêu cầu.<br>C — thiếu mạo từ "the" bắt buộc trước so sánh nhất khi đi cùng danh từ đếm được số ít "method".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>controlling idea</i>: ý chính, luận điểm; <i>employ</i> /ɪmˈplɔɪ/ (v): sử dụng, áp dụng; <i>common</i> /ˈkɒmən/ (adj): phổ biến.</div>`},

{id:24,type:'fill',q:`My neighbor is driving me mad! It seems that __________ it is at night, __________ he plays his music!`,vi:`Hàng xóm của tôi khiến tôi phát điên! Có vẻ như đêm càng khuya thì anh ta càng mở nhạc to hơn!`,opts:["A. the less/the more loud","B. the less/less","C. the more late/the more loudly","D. the later/the louder"],ans:3,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: D. the later/the louder</div><div class="ex-card mb-2">The later it is at night, the louder he plays his music!</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Cấu trúc đồng tiến với 2 tính từ/trạng từ ngắn: "late" → "the later"; "loud" → "the louder" (đều thêm -er trực tiếp vì là từ ngắn 1 âm tiết).</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — "the less" sai nghĩa (không liên quan đến "khuya"), và "the more loud" sai vì "loud" là từ ngắn phải dùng "-er".<br>B — hoàn toàn sai nghĩa và thiếu "the" ở vế 2.<br>C — "the more late" sai vì "late" là từ ngắn (dùng "-er"); "the more loudly" tuy đúng dạng nhưng "loudly" là trạng từ trong khi câu cần bổ nghĩa cho hành động chơi nhạc — thực tế "louder" (dùng như trạng từ so sánh của loud) tự nhiên và phổ biến hơn trong văn nói.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>drive someone mad</i>: làm ai đó phát điên; <i>late</i> /leɪt/ (adj/adv): muộn, khuya; <i>loud</i> /laʊd/ (adj/adv): to, ồn.</div>`},

{id:25,type:'fill',q:`It gets __________ when the winter is coming.`,vi:`Trời trở nên lạnh hơn khi mùa đông đang đến.`,opts:["A. cold and cold","B. the coldest and coldest","C. colder and colder","D. more and more cold"],ans:2,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: C. colder and colder</div><div class="ex-card mb-2">It gets colder and colder when the winter is coming.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> So sánh lũy tiến với động từ "get" diễn tả sự thay đổi tăng dần. "Cold" là tính từ ngắn → thêm "-er", lặp lại 2 lần nối bằng "and": colder and colder.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — thiếu dạng so sánh (-er), chỉ lặp lại tính từ nguyên thể, sai cấu trúc lũy tiến.<br>B — "the coldest" là so sánh nhất, không dùng trong cấu trúc lũy tiến; cũng không nhất quán khi kết hợp với "coldest".<br>D — "cold" là tính từ ngắn, không dùng "more...cold" mà phải dùng "colder".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>cold</i> /koʊld/ (adj): lạnh; <i>get + adj</i>: trở nên...</div>`},

{id:26,type:'fill',q:`The cuisine of France is __________.`,vi:`Ẩm thực Pháp nổi tiếng hơn ẩm thực Anh.`,opts:["A. more famous than that of England","B. famous than the cuisine of England","C. more famous than which of England","D. as famous than that of England"],ans:0,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: A. more famous than that of England</div><div class="ex-card mb-2">The cuisine of France is more famous than that of England.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> "Famous" là tính từ dài → "more famous than". Dùng đại từ thay thế "that" (số ít) để thay cho "the cuisine" đã nhắc ở trước, tránh lặp từ: "that of England" = "the cuisine of England".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>B — thiếu từ "more" cần thiết trước tính từ dài "famous" để tạo so sánh hơn.<br>C — "which" không dùng để thay thế danh từ theo cách này, phải dùng đại từ chỉ định "that".<br>D — "as...than" là kết hợp sai ngữ pháp, "as" chỉ đi với "as" (so sánh bằng), không đi với "than".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>cuisine</i> /kwɪˈziːn/ (n): nền ẩm thực; <i>famous</i> /ˈfeɪməs/ (adj): nổi tiếng; đại từ thay thế "that/those" dùng để tránh lặp danh từ đã nhắc.</div>`},

{id:27,type:'fill',q:`My sister is two years __________ than me.`,vi:`Chị tôi kém tôi hai tuổi (trẻ hơn tôi hai tuổi).`,opts:["A. young","B. so young","C. younger","D. the youngest"],ans:2,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: C. younger</div><div class="ex-card mb-2">My sister is two years younger than me.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Cấu trúc so sánh hơn có số lượng cụ thể chỉ mức chênh lệch: S + V + (number) + adj-er + than + S2. "Young" là tính từ ngắn → thêm "-er": younger, đi cùng "than".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A, B — tính từ nguyên thể/nhấn mạnh, không mang nghĩa so sánh và không đi được với "than".<br>D — "the youngest" là so sánh nhất, sai vì câu chỉ so sánh 2 người (chị và tôi), cần so sánh hơn.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>young</i> /jʌŋ/ (adj): trẻ; cấu trúc "số lượng + adj-er + than" để chỉ mức chênh lệch cụ thể.</div>`},

{id:28,type:'fill',q:`What is the __________ movie you have ever seen?`,vi:`Bộ phim tệ nhất mà bạn từng xem là phim gì?`,opts:["A. worst","B. baddest","C. most bad","D. the worst"],ans:0,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: A. worst</div><div class="ex-card mb-2">What is the worst movie you have ever seen?</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Cụm "...you have ever seen" là dấu hiệu so sánh nhất. "Bad" có dạng so sánh nhất bất quy tắc là "worst"; mạo từ "the" đã có sẵn trong câu hỏi ("the ___ movie") nên chỉ cần điền "worst".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>B — "baddest" không tồn tại vì "bad" là tính từ bất quy tắc, không thêm "-est" thông thường.<br>C — "most bad" sai vì "bad" không dùng với "most", phải dùng dạng bất quy tắc "worst".<br>D — thừa "the" vì câu đã có sẵn "the" phía trước chỗ trống ("the ___ movie"), thêm "the" nữa sẽ bị lặp.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>bad</i> /bæd/ (adj): tệ, dở → so sánh nhất bất quy tắc: <i>worst</i> /wɜːrst/.</div>`},

{id:29,type:'fill',q:`The Missouri River is the __________ river in the United States.`,vi:`Sông Missouri là con sông dài nhất nước Mỹ.`,opts:["A. most long","B. longer","C. longest","D. the longer"],ans:2,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: C. longest</div><div class="ex-card mb-2">The Missouri River is the longest river in the United States.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> So sánh sông Missouri với TẤT CẢ các con sông khác ở Mỹ → so sánh nhất. "Long" là tính từ ngắn → thêm "-est": longest (mạo từ "the" đã có sẵn trong câu).</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — "long" là tính từ ngắn (1 âm tiết), không dùng "most", phải dùng "-est".<br>B, D — "longer" là so sánh hơn, sai vì đây là so sánh với cả một tập hợp (tất cả sông ở Mỹ), cần so sánh nhất "longest".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>river</i> /ˈrɪvər/ (n): con sông; <i>long</i> /lɔːŋ/ (adj): dài.</div>`},

{id:30,type:'fill',q:`That whale is __________ than this dingo.`,vi:`Con cá voi đó to hơn con chó dingo này.`,opts:["A. big","B. most big","C. biggest","D. bigger"],ans:3,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: D. bigger</div><div class="ex-card mb-2">That whale is bigger than this dingo.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Có "than" ở sau → cần dạng so sánh hơn. "Big" tận cùng 1 phụ âm sau 1 nguyên âm (tính từ ngắn 1 âm tiết) → gấp đôi phụ âm cuối, thêm "-er": bigger.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — tính từ nguyên thể, không thể đi trực tiếp với "than" để so sánh.<br>B — "most big" sai vì "big" là tính từ ngắn, không dùng "most", và "most" cũng không đi với "than".<br>C — "biggest" là so sánh nhất, không đi kèm "than" (so sánh nhất dùng với "in/of" hoặc phạm vi, không dùng "than").</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>whale</i> /weɪl/ (n): cá voi; <i>dingo</i> /ˈdɪŋɡoʊ/ (n): chó hoang Úc; <i>big</i> /bɪɡ/ (adj): to, lớn.</div>`}
];

const COMPARISON_EX2 = [
{id:1,type:'fill',q:`She sings ________________ a professional singer.`,vi:`Cô ấy hát hay như một ca sĩ chuyên nghiệp.`,opts:["A. as beautifully as","B. as beautiful as","C. more beautiful than","D. so beautifully as"],ans:0,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: A. as beautifully as</div><div class="ex-card mb-2">She sings as beautifully as a professional singer.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> "Sings" là động từ, cần trạng từ đứng sau để bổ nghĩa cho cách hát → dùng "beautifully" (trạng từ). Cấu trúc so sánh bằng khẳng định: as + adv + as.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>B — "beautiful" là tính từ, không thể bổ nghĩa cho động từ "sings".<br>C — "more beautiful than" là so sánh hơn với tính từ, sai cả từ loại lẫn cấu trúc (câu này là so sánh bằng, không phải hơn).<br>D — "so...as" chỉ dùng ở dạng phủ định, câu này là khẳng định nên phải dùng "as...as".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>professional</i> /prəˈfeʃənl/ (adj): chuyên nghiệp; <i>beautifully</i> /ˈbjuːtɪfli/ (adv): một cách hay/đẹp.</div>`},

{id:2,type:'fill',q:`The new smartphone costs _________________ the previous model.`,vi:`Chiếc điện thoại thông minh mới có giá bằng một nửa mẫu trước đó.`,opts:["A. half as much as","B. as half much as","C. half as many as","D. as half many as"],ans:0,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: A. half as much as</div><div class="ex-card mb-2">The new smartphone costs half as much as the previous model.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> "Cost" (giá tiền) là danh từ/khái niệm không đếm được → dùng "much". "Half" (phân số chỉ số lần) đứng TRƯỚC "as much as": half + as much as.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>B — sai vị trí của "half", phải đặt trước cụm "as...as", không chen vào giữa.<br>C — "many" dùng cho danh từ đếm được, nhưng "giá tiền" ở đây mang tính không đếm được → phải dùng "much".<br>D — vừa sai vị trí "half" vừa sai "many" thay vì "much".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>previous</i> /ˈpriːviəs/ (adj): trước đó; <i>half</i> /hæf/: một nửa (số nhân dùng trong so sánh gấp lần).</div>`},

{id:3,type:'fill',q:`She studies ___________ the other students before the exams.`,vi:`Cô ấy học chăm chỉ hơn các bạn học sinh khác trước kỳ thi.`,opts:["A. more hardly than","B. harder than","C. the hardest","D. as hardly as"],ans:1,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: B. harder than</div><div class="ex-card mb-2">She studies harder than the other students before the exams.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> "Hard" ở đây là trạng từ nghĩa "chăm chỉ, cật lực" và có dạng so sánh hơn ngắn (thêm -er trực tiếp): harder, kèm "than".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — "hardly" là một từ khác nghĩa hoàn toàn (nghĩa là "hầu như không"), không liên quan đến "chăm chỉ", và cũng không dùng với "more" vì "hard" là từ ngắn.<br>C — "the hardest" là so sánh nhất, sai vì câu chỉ so sánh với "the other students" (một nhóm cụ thể được nêu ra để so sánh hơn, không phải so sánh với tất cả).<br>D — "as hardly as" vừa sai nghĩa (hardly ≠ hard) vừa sai cấu trúc so sánh (câu cần so sánh hơn, không phải so sánh bằng).</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>hard</i> /hɑːrd/ (adv): chăm chỉ, cật lực; <i>hardly</i> /ˈhɑːrdli/ (adv): hầu như không — hai từ dễ nhầm lẫn!</div>`},

{id:4,type:'fill',q:`The tropical beach is ____________ place to spend a vacation.`,vi:`Bãi biển nhiệt đới là nơi thư giãn nhất để nghỉ dưỡng.`,opts:["A. the more relaxing","B. more relaxing","C. the most relaxing","D. as relaxing as"],ans:2,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: C. the most relaxing</div><div class="ex-card mb-2">The tropical beach is the most relaxing place to spend a vacation.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Câu ngụ ý so sánh với TẤT CẢ những nơi khác để nghỉ dưỡng → so sánh nhất. "Relaxing" là tính từ dài (V-ing dùng như tính từ, 3 âm tiết) → "the most relaxing".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A, B — "more relaxing" (có hoặc không "the") là so sánh hơn, thiếu "than" và không phù hợp ý nghĩa "nhất trong tất cả".<br>D — "as relaxing as" là so sánh bằng, cần vế so sánh thứ hai (as...as + N), không phù hợp với cấu trúc câu này.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>tropical</i> /ˈtrɒpɪkl/ (adj): (thuộc) nhiệt đới; <i>relaxing</i> /rɪˈlæksɪŋ/ (adj): thư giãn, thư thái.</div>`},

{id:5,type:'fill',q:`Her aunt gave her a _____________ handbag on her birthday last week.`,vi:`Dì cô ấy đã tặng cô ấy một chiếc túi xách Hàn Quốc màu đỏ xinh đẹp vào sinh nhật tuần trước.`,opts:["A. beautiful red Korean","B. red Korean beautiful","C. beautiful Korean red","D. Korean red beautiful"],ans:0,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: A. beautiful red Korean</div><div class="ex-card mb-2">Her aunt gave her a beautiful red Korean handbag.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Trật tự tính từ chuẩn OSASCOMP: <b>O</b>pinion (beautiful) → Size → Age → Shape → <b>C</b>olor (red) → <b>O</b>rigin (Korean) → Material → Purpose. Vậy thứ tự đúng là: beautiful (ý kiến) — red (màu sắc) — Korean (nguồn gốc).</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>B — đặt "red" (màu sắc) lên trước "beautiful" (ý kiến), sai vì tính từ chỉ ý kiến luôn đứng đầu tiên.<br>C — đặt "Korean" (nguồn gốc) trước "red" (màu sắc), sai vì màu sắc phải đứng trước nguồn gốc.<br>D — đặt "Korean" và "red" trước "beautiful" hoàn toàn ngược trật tự chuẩn.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>handbag</i> /ˈhændbæg/ (n): túi xách tay; quy tắc <b>OSASCOMP</b> (Opinion-Size-Age-Shape-Color-Origin-Material-Purpose).</div>`},

{id:6,type:'fill',q:`He hopes that she will be happy with this ___________ring.`,vi:`Anh ấy hy vọng cô ấy sẽ hài lòng với chiếc nhẫn Indonesia nhỏ xinh này.`,opts:["A. small nice Indonesian","B. nice small Indonesian","C. Indonesian nice small","D. nice Indonesian small"],ans:1,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: B. nice small Indonesian</div><div class="ex-card mb-2">He hopes that she will be happy with this nice small Indonesian ring.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Theo OSASCOMP: Opinion (nice) → Size (small) → Origin (Indonesian). Ý kiến luôn đứng đầu, kích thước đứng sau ý kiến, nguồn gốc đứng gần danh từ nhất trong 3 loại này.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — đặt "small" (kích thước) trước "nice" (ý kiến), sai trật tự vì ý kiến phải đứng trước.<br>C — đặt "Indonesian" (nguồn gốc) lên đầu tiên, sai hoàn toàn vì nguồn gốc luôn đứng gần danh từ nhất trong nhóm này.<br>D — đặt "Indonesian" trước "small", sai vì kích thước phải đứng trước nguồn gốc.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>ring</i> /rɪŋ/ (n): chiếc nhẫn; <i>nice</i> /naɪs/ (adj): tốt, đẹp, dễ chịu (tính từ chỉ ý kiến).</div>`},

{id:7,type:'fill',q:`She is ____________ at solving puzzles than her brother.`,vi:`Cô ấy giỏi giải câu đố hơn anh trai mình.`,opts:["A. more clever","B. cleverer","C. the cleverest","D. as clever"],ans:1,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: B. cleverer</div><div class="ex-card mb-2">She is cleverer at solving puzzles than her brother.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> "Clever" là tính từ 2 âm tiết nhưng tận cùng bằng đuôi <b>-er</b> — một trong 5 đuôi đặc biệt khiến nó được coi là tính từ NGẮN → chỉ cần thêm "-er": cleverer, không dùng "more".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — sai vì "clever" thuộc nhóm tính từ ngắn đặc biệt (đuôi -er), không dùng "more" mà phải thêm "-er" trực tiếp vào từ.<br>C — "the cleverest" là so sánh nhất, sai vì câu chỉ so sánh giữa 2 người (cô ấy và anh trai), cần so sánh hơn.<br>D — thiếu "than" cần thiết, và "as clever" là so sánh bằng trong khi câu này cần so sánh hơn.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>clever</i> /ˈklevər/ (adj): thông minh, lanh lợi; <i>puzzle</i> /ˈpʌzl/ (n): câu đố.</div>`},

{id:8,type:'fill',q:`The _________ we go, the more beautiful the scenery becomes.`,vi:`Chúng ta đi càng xa thì phong cảnh càng đẹp.`,opts:["A. farer","B. farest","C. farther","D. farthest"],ans:2,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: C. farther</div><div class="ex-card mb-2">The farther we go, the more beautiful the scenery becomes.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Cấu trúc so sánh đồng tiến cần dạng so sánh HƠN ở cả hai vế. "Far" là tính từ/trạng từ bất quy tắc, dạng so sánh hơn là "farther" (khoảng cách vật lý) hoặc "further" (khoảng cách trừu tượng).</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A, B — "farer" và "farest" không tồn tại vì "far" là từ bất quy tắc, không thêm "-er/-est" thông thường.<br>D — "farthest" là so sánh nhất, sai vì cấu trúc đồng tiến ("the more beautiful" ở vế sau) cần so sánh hơn, không phải so sánh nhất.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>scenery</i> /ˈsiːnəri/ (n): phong cảnh; <i>far</i> /fɑːr/ → so sánh hơn bất quy tắc: <i>farther/further</i>.</div>`},

{id:9,type:'fill',q:`The dishes he prepares are getting_______________.`,vi:`Những món ăn anh ấy chuẩn bị ngày càng ngon hơn.`,opts:["A. more and more delicious","B. most and most delicious","C. the more and the more delicious","D. the most delicious"],ans:0,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: A. more and more delicious</div><div class="ex-card mb-2">The dishes he prepares are getting more and more delicious.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Đây là so sánh lũy tiến (càng ngày càng) với động từ "get/become". "Delicious" là tính từ dài (3 âm tiết) → dùng "more and more + adj".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>B — "most" không dùng trong cấu trúc lũy tiến, cấu trúc này chỉ dùng "more/less and more/less".<br>C — thừa "the", cấu trúc lũy tiến không cần mạo từ "the" trước "more".<br>D — "the most delicious" là so sánh nhất, không diễn tả được ý "ngày càng" (tăng dần theo thời gian) mà câu yêu cầu.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>dish</i> /dɪʃ/ (n): món ăn; <i>delicious</i> /dɪˈlɪʃəs/ (adj): ngon.</div>`},

{id:10,type:'fill',q:`She doesn't have ___________ as her friend has.`,vi:`Cô ấy không có nhiều sách bằng bạn của mình.`,opts:["A. as much books","B. more books","C. so books","D. as many books"],ans:3,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: D. as many books</div><div class="ex-card mb-2">She doesn't have as many books as her friend has.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> "Books" là danh từ đếm được số nhiều → dùng "many" (không dùng "much" vốn dành cho danh từ không đếm được). Cấu trúc so sánh bằng phủ định: S + V(phủ định) + as many + N(số nhiều) + as + S2.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — "much" dùng cho danh từ không đếm được, nhưng "books" là danh từ đếm được → phải dùng "many".<br>B — "more books" là so sánh hơn, thiếu "as" và không đi với "as...has" phía sau, sai cấu trúc câu.<br>C — "so books" thiếu từ "many" cần thiết, không tạo thành cụm danh từ hợp lệ.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>many</i>: nhiều (dùng cho danh từ đếm được); <i>much</i>: nhiều (dùng cho danh từ không đếm được).</div>`},

{id:11,type:'fill',q:`Giang is 1.51 meters tall, and Hien is 1.60 meters tall. Giang is _________ Hien.`,vi:`Giang cao 1,51 mét, còn Hiên cao 1,60 mét. Giang thấp hơn Hiên.`,opts:["A. older than","B. shorter than","C. taller than","D. younger than"],ans:1,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: B. shorter than</div><div class="ex-card mb-2">Giang is shorter than Hien.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Dữ kiện cho biết Giang (1.51m) thấp hơn Hiên (1.60m) → dùng so sánh hơn của "short": shorter than, dựa theo dữ kiện chiều cao trong câu, không phải tuổi tác.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A, D — "older/younger" nói về tuổi tác, không liên quan đến dữ kiện chiều cao được cho trong câu.<br>C — "taller than" sai nghĩa hoàn toàn ngược lại, vì Giang thấp hơn (1.51m < 1.60m) chứ không cao hơn Hiên.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>tall</i> /tɔːl/ (adj): cao → so sánh hơn: <i>taller</i>; trái nghĩa <i>short</i> /ʃɔːrt/ (adj): thấp → <i>shorter</i>.</div>`},

{id:12,type:'fill',q:`The more talkative she was, __________ uncomfortable we left.`,vi:`Cô ấy càng nói nhiều thì chúng tôi rời đi càng cảm thấy khó chịu.`,opts:["A. more than","B. the more than","C. the better than","D. the more"],ans:3,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: D. the more</div><div class="ex-card mb-2">The more talkative she was, the more uncomfortable we left.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Vế đầu "The more talkative she was" là so sánh đồng tiến → vế sau cũng cần "the more" đứng trước tính từ dài "uncomfortable" để tạo cấu trúc song song: "the more uncomfortable".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — thiếu "the" bắt buộc ở đầu vế trong cấu trúc đồng tiến.<br>B — thừa từ "than", cấu trúc đồng tiến không dùng "than" mà dùng dấu phẩy nối hai vế.<br>C — "the better" sai vì không khớp nghĩa với "uncomfortable" đã có sẵn trong câu (không cần thêm tính từ khác), và cũng thừa "than".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>talkative</i> /ˈtɔːkətɪv/ (adj): nói nhiều, lắm lời; <i>uncomfortable</i> /ʌnˈkʌmftəbl/ (adj): khó chịu, không thoải mái.</div>`},

{id:13,type:'fill',q:`My father was given a ____________ armchair by his best friend.`,vi:`Bố tôi được bạn thân tặng cho một chiếc ghế bành da mới tuyệt vời.`,opts:["A. wonderful new leather","B. new wonderful leather","C. leather new wonderful","D. wonderful leather new"],ans:0,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: A. wonderful new leather</div><div class="ex-card mb-2">My father was given a wonderful new leather armchair.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Theo OSASCOMP: Opinion (wonderful) → Age (new) → Material (leather). Ý kiến luôn đứng đầu tiên, tuổi/tình trạng đứng trước chất liệu, chất liệu đứng gần danh từ nhất.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>B — đặt "new" (tuổi) trước "wonderful" (ý kiến), sai vì ý kiến phải đứng đầu tiên.<br>C — đặt "leather" (chất liệu) lên đầu tiên, sai hoàn toàn vì chất liệu luôn đứng gần danh từ nhất, không đứng đầu.<br>D — đặt "leather" trước "new", sai vì tuổi/tình trạng phải đứng trước chất liệu.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>armchair</i> /ˈɑːrmtʃer/ (n): ghế bành (có tay vịn); <i>leather</i> /ˈleðər/ (n/adj): da (chất liệu).</div>`},

{id:14,type:'fill',q:`__________ comfortable I feel, the more creative I am.`,vi:`Tôi càng cảm thấy thoải mái thì tôi càng sáng tạo.`,opts:["A. Most","B. More","C. Most of","D. The more"],ans:3,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: D. The more</div><div class="ex-card mb-2">The more comfortable I feel, the more creative I am.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Đầu câu bắt đầu vế đầu của cấu trúc đồng tiến, bắt buộc có "The more" đứng trước tính từ dài "comfortable" để khớp với vế sau "the more creative".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A, B — thiếu "the" bắt buộc ở đầu vế của cấu trúc đồng tiến.<br>C — "Most of" thường đi với danh từ (most of the students), không phù hợp để đứng trước tính từ "comfortable" trong cấu trúc này.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>comfortable</i> /ˈkʌmftəbl/ (adj): thoải mái; <i>creative</i> /kriˈeɪtɪv/ (adj): sáng tạo.</div>`},

{id:15,type:'fill',q:`Mary is more intelligent than her brother.`,vi:`Mary thông minh hơn anh trai cô ấy. → Chọn câu có nghĩa gần đúng nhất.`,opts:["A. Mary isn't as intelligent as her brother.","B. Mary's brother is more intelligent than she is.","C. Mary's brother isn't as intelligent as she is.","D. Mary is less intelligent than her brother."],ans:2,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: C. Mary's brother isn't as intelligent as she is.</div><div class="ex-card mb-2">Mary is more intelligent than her brother. = Mary's brother isn't as intelligent as she is.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Câu gốc: Mary THÔNG MINH HƠN anh trai. Chuyển sang so sánh bằng phủ định với chủ ngữ là anh trai: "anh trai KHÔNG thông minh bằng Mary" — giữ nguyên nghĩa gốc.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — sai nghĩa hoàn toàn, câu này nói Mary kém thông minh hơn anh trai, ngược với câu gốc.<br>B — sai nghĩa, đảo ngược vai trò so sánh (nói anh trai thông minh hơn Mary).<br>D — "less intelligent" nghĩa là Mary kém thông minh hơn, trái ngược hoàn toàn với câu gốc "more intelligent".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>intelligent</i> /ɪnˈtelɪdʒənt/ (adj): thông minh; mẹo chuyển đổi: "A hơn B" = "B không bằng A" (as...as phủ định).</div>`},

{id:16,type:'fill',q:`This book is _______________ than the last one I read.`,vi:`Cuốn sách này thú vị hơn cuốn cuối cùng tôi đã đọc.`,opts:["A. as interesting","B. more interesting","C. most interesting","D. interesting"],ans:1,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: B. more interesting</div><div class="ex-card mb-2">This book is more interesting than the last one I read.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Có "than" ở sau → cần dạng so sánh hơn. "Interesting" là tính từ dài (V-ing, 4 âm tiết) → "more interesting".</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — "as interesting" thiếu "as" thứ hai và không đi với "than" (so sánh bằng không dùng "than").<br>C — "most interesting" là so sánh nhất, không đi kèm "than" — so sánh nhất dùng với "in/of", không dùng "than".<br>D — tính từ nguyên thể, không thể hiện ý so sánh, không đi trực tiếp được với "than".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>interesting</i> /ˈɪntrəstɪŋ/ (adj): thú vị, hấp dẫn.</div>`},

{id:17,type:'fill',q:`The performance last night was _____________________the one we saw last month.`,vi:`Buổi biểu diễn tối qua hay ngang với buổi mà chúng tôi đã xem tháng trước.`,opts:["A. as good as","B. more better than","C. the best","D. most better"],ans:0,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: A. as good as</div><div class="ex-card mb-2">The performance last night was as good as the one we saw last month.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Câu diễn tả 2 buổi biểu diễn NGANG NHAU về chất lượng → dùng so sánh bằng: as + adj + as. "Good" giữ nguyên dạng gốc trong cấu trúc as...as (không chia so sánh).</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>B — "more better" là lỗi so sánh kép nghiêm trọng (kết hợp cả "more" và dạng so sánh hơn bất quy tắc "better"), hoàn toàn sai ngữ pháp.<br>C — "the best" là so sánh nhất, sai nghĩa vì câu chỉ so sánh 2 buổi biểu diễn bằng nhau, không phải nhất trong nhiều buổi.<br>D — "most better" cũng là lỗi so sánh kép tương tự B, sai ngữ pháp nghiêm trọng.</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>performance</i> /pərˈfɔːrməns/ (n): buổi biểu diễn; lưu ý: không bao giờ kết hợp "more/most" với dạng bất quy tắc "better/best".</div>`},

{id:18,type:'fill',q:`The museum is less crowded during weekdays ________ on weekends.`,vi:`Bảo tàng ít đông đúc hơn vào các ngày trong tuần so với vào cuối tuần.`,opts:["A. as","B. than","C. the","D. more"],ans:1,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: B. than</div><div class="ex-card mb-2">The museum is less crowded during weekdays than on weekends.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> "Less + adj" là dạng so sánh hơn (ở mức kém hơn), phải đi kèm với "than" để hoàn chỉnh cấu trúc so sánh: less + adj + than.</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — "as" chỉ dùng trong so sánh bằng (as...as), không đi cùng "less" (dạng so sánh hơn).<br>C — "the" không cần thiết ở đây và không tạo thành cấu trúc so sánh hợp lệ.<br>D — "more" bị thừa và mâu thuẫn về nghĩa vì câu đã có "less" rồi (không thể có cả less và more cùng lúc).</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>crowded</i> /ˈkraʊdɪd/ (adj): đông đúc; <i>weekday</i> /ˈwiːkdeɪ/ (n): ngày trong tuần (từ thứ Hai đến thứ Sáu).</div>`},

{id:19,type:'fill',q:`His grades are __________ than they were last semester.`,vi:`Điểm số của anh ấy tệ hơn so với học kỳ trước.`,opts:["A. badder","B. worst","C. more bad","D. worse"],ans:3,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: D. worse</div><div class="ex-card mb-2">His grades are worse than they were last semester.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Có "than" → cần so sánh hơn. "Bad" là tính từ bất quy tắc, dạng so sánh hơn là "worse" (không theo quy tắc thông thường).</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>A — "badder" không tồn tại vì "bad" là từ bất quy tắc, không thêm "-er" thông thường.<br>B — "worst" là so sánh nhất, sai vì đi kèm "than" (so sánh nhất không dùng với "than").<br>C — "more bad" sai vì "bad" không dùng với "more", phải dùng dạng bất quy tắc "worse".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>grade</i> /ɡreɪd/ (n): điểm số; <i>semester</i> /sɪˈmestər/ (n): học kỳ; <i>bad</i> → so sánh hơn bất quy tắc: <i>worse</i> /wɜːrs/.</div>`},

{id:20,type:'fill',q:`She sings ____________than anyone I know.`,vi:`Cô ấy hát hay hơn bất kỳ ai mà tôi biết.`,opts:["A. more beautifully","B. most beautifully","C. as beautiful","D. beautifully"],ans:0,
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: A. more beautifully</div><div class="ex-card mb-2">She sings more beautifully than anyone I know.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> "Sings" cần trạng từ bổ nghĩa → "beautifully" (trạng từ dài, 4 âm tiết) → dạng so sánh hơn là "more beautifully", đi kèm "than" (cấu trúc "more...than anyone" diễn tả ý nghĩa vượt trội tương tự so sánh nhất nhưng vẫn dùng dạng so sánh hơn về mặt ngữ pháp).</div><div class="mb-2"><b class="text-dark2">❌ Loại các đáp án khác:</b><br>B — "most beautifully" là so sánh nhất, không đi kèm "than" theo đúng ngữ pháp chuẩn.<br>C — "beautiful" là tính từ, không bổ nghĩa được cho động từ "sings"; đồng thời thiếu "as" thứ hai.<br>D — thiếu từ "more" cần thiết để tạo thành so sánh hơn khi đi với "than".</div><div class="mb-2"><b class="text-dark2">📚 Từ mới:</b> <i>anyone</i> /ˈeniwʌn/ (pron): bất kỳ ai; cấu trúc "more...than anyone (else)" nhấn mạnh sự vượt trội.</div>`}
];

const COMPARISON_EX3 = [
{id:1,type:'typing',q:`Rewrite the sentence beginning with the given words, keeping the same meaning.<br><b>It is hotter today than it was yesterday.</b><br>=&gt; It was ______________________________________.`,vi:`Hôm nay trời nóng hơn hôm qua.`,answer:`not as hot yesterday as it is today`,accept:["not as hot yesterday as it is today","not as hot yesterday as today","not as hot yesterday as it is today.","not as hot yesterday as today."],
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: It was <b>not as hot yesterday as it is today</b>.</div><div class="ex-card mb-2">It is hotter today than it was yesterday. = It was not as hot yesterday as it is today.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Chuyển so sánh hơn (S + be + adj-er + than) sang so sánh bằng phủ định: S + be + not as + adj + as. Câu gốc "hotter today than yesterday" nghĩa là "yesterday KHÔNG nóng bằng today".</div><div class="mb-2"><b class="text-dark2">💡 Phân tích từng bước:</b> Giữ nguyên 2 mốc thời gian, chỉ đảo vai trò: chủ ngữ mới là "it" (chỉ thời tiết hôm qua), động từ "was" (quá khứ vì "yesterday"), phủ định "not as hot as" + mốc còn lại "it is today".</div><div class="mb-2"><b class="text-dark2">✅ Các cách diễn đạt khác cũng được chấp nhận:</b> "It wasn't as hot yesterday as it is today."</div><div class="mb-2"><b class="text-dark2">📚 Từ vựng cần lưu ý:</b> <b>hot</b> /hɒt/ (adj): nóng — dạng so sánh hơn "hotter", so sánh bằng "as hot as"</div>`},

{id:2,type:'typing',q:`Rewrite the sentence beginning with the given words, keeping the same meaning.<br><b>My father is the fattest in my family.</b><br>=&gt; No one ______________________________________.`,vi:`Bố tôi là người mập nhất trong gia đình tôi.`,answer:`in my family is fatter than my father`,accept:["in my family is fatter than my father","in my family is fatter than my father.","in my family is as fat as my father","in my family is as fat as my father."],
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: No one <b>in my family is fatter than my father</b>.</div><div class="ex-card mb-2">My father is the fattest in my family. = No one in my family is fatter than my father.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Chuyển so sánh nhất (S + be + the + adj-est) sang so sánh hơn phủ định toàn bộ: No one + be + adj-er + than + S.</div><div class="mb-2"><b class="text-dark2">💡 Phân tích từng bước:</b> "The fattest in my family" = không ai trong gia đình mập hơn bố tôi → "No one in my family is fatter than my father".</div><div class="mb-2"><b class="text-dark2">✅ Cách diễn đạt khác cũng được chấp nhận:</b> "No one in my family is as fat as my father."</div><div class="mb-2"><b class="text-dark2">📚 Từ vựng cần lưu ý:</b> <b>fat</b> /fæt/ (adj): béo, mập — so sánh nhất "the fattest"; <b>no one</b>: không ai (đại từ phủ định, luôn chia động từ số ít)</div>`},

{id:3,type:'typing',q:`Rewrite the sentence beginning with the given words, keeping the same meaning.<br><b>Jane cooks better than her sister.</b><br>=&gt; Jane's sister ______________________________________.`,vi:`Jane nấu ăn giỏi hơn chị/em gái cô ấy.`,answer:`doesn't cook as well as Jane`,accept:["doesn't cook as well as jane","does not cook as well as jane","doesn't cook as well as jane.","does not cook as well as jane.","doesn't cook as well as jane does","does not cook as well as jane does"],
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: Jane's sister <b>doesn't cook as well as Jane</b>.</div><div class="ex-card mb-2">Jane cooks better than her sister. = Jane's sister doesn't cook as well as Jane.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> "Cook" là động từ nên so sánh hơn dùng trạng từ "well" → "better". Chuyển sang so sánh bằng phủ định: S + doesn't/don't + V + as well as + O.</div><div class="mb-2"><b class="text-dark2">💡 Phân tích từng bước:</b> Đổi chủ ngữ từ "Jane" sang "Jane's sister", phủ định động từ "cooks" → "doesn't cook", giữ "as well as Jane".</div><div class="mb-2"><b class="text-dark2">✅ Cách diễn đạt khác cũng được chấp nhận:</b> "Jane's sister doesn't cook as well as Jane does."</div><div class="mb-2"><b class="text-dark2">📚 Từ vựng cần lưu ý:</b> <b>cook</b> /kʊk/ (v): nấu ăn; <b>well</b> /wel/ (adv, dạng trạng từ của "good"): giỏi, tốt — so sánh hơn "better"</div>`},

{id:4,type:'typing',q:`Rewrite the sentence beginning with the given words, keeping the same meaning.<br><b>Tom is the best guitar player I've ever known.</b><br>=&gt; I've ______________________________________.`,vi:`Tom là người chơi đàn guitar giỏi nhất mà tôi từng biết.`,answer:`never known a better guitar player than Tom`,accept:["never known a better guitar player than tom","never known a better guitar player than tom.","never known such a good guitar player as tom"],
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: I've <b>never known a better guitar player than Tom</b>.</div><div class="ex-card mb-2">Tom is the best guitar player I've ever known. = I've never known a better guitar player than Tom.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> So sánh nhất "the best...I've ever known" chuyển thành hiện tại hoàn thành phủ định + so sánh hơn: S + have/has + never + known + a better + N + than.</div><div class="mb-2"><b class="text-dark2">💡 Phân tích từng bước:</b> "The best guitar player I've ever known" = "tôi chưa từng biết ai chơi guitar giỏi hơn Tom" → "I've never known a better guitar player than Tom".</div><div class="mb-2"><b class="text-dark2">✅ Cách diễn đạt khác cũng được chấp nhận:</b> "I've never known such a good guitar player as Tom."</div><div class="mb-2"><b class="text-dark2">📚 Từ vựng cần lưu ý:</b> <b>guitar player</b> /ɡɪˈtɑːr ˈpleɪər/ (n): người chơi đàn ghi-ta; <b>ever</b> /ˈevər/ (adv): từng, đã từng (dùng với thì hiện tại hoàn thành)</div>`},

{id:5,type:'typing',q:`Rewrite the sentence beginning with the given words, keeping the same meaning.<br><b>This house is not as big and new as other houses on this street.</b><br>=&gt; Other houses ______________________________________.`,vi:`Ngôi nhà này không to và mới bằng những ngôi nhà khác trên phố này.`,answer:`on this street are bigger and newer than this house`,accept:["on this street are bigger and newer than this house","on this street are bigger and newer than this one","on this street are bigger and newer than this house.","on this street are bigger and newer than this one."],
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: Other houses <b>on this street are bigger and newer than this house</b>.</div><div class="ex-card mb-2">This house is not as big and new as other houses on this street. = Other houses on this street are bigger and newer than this house.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Chuyển so sánh bằng phủ định (not as...as) sang so sánh hơn khẳng định: đảo chủ ngữ, tính từ ngắn thêm "-er" (big→bigger, new→newer), thêm "than".</div><div class="mb-2"><b class="text-dark2">💡 Phân tích từng bước:</b> Chủ ngữ mới "Other houses on this street", tính từ "big and new" → "bigger and newer", đối tượng so sánh còn lại "this house".</div><div class="mb-2"><b class="text-dark2">✅ Cách diễn đạt khác cũng được chấp nhận:</b> "Other houses on this street are bigger and newer than this one."</div><div class="mb-2"><b class="text-dark2">📚 Từ vựng cần lưu ý:</b> <b>big</b> /bɪɡ/ (adj): to, lớn — so sánh hơn "bigger"; <b>new</b> /njuː/ (adj): mới — so sánh hơn "newer"</div>`},

{id:6,type:'typing',q:`Rewrite the sentence beginning with the given words, keeping the same meaning.<br><b>Mr. Parker is younger than he looks.</b><br>=&gt; Mr. Parker looks ______________________________________.`,vi:`Ông Parker trẻ hơn so với vẻ ngoài của ông ấy.`,answer:`older than he is`,accept:["older than he is","older than he is."],
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: Mr. Parker looks <b>older than he is</b>.</div><div class="ex-card mb-2">Mr. Parker is younger than he looks. = Mr. Parker looks older than he is.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Đảo ngược 2 vế so sánh và đổi tính từ trái nghĩa: "younger...than he looks" (thực tế trẻ hơn vẻ ngoài) = "looks older than he is" (trông già hơn tuổi thật).</div><div class="mb-2"><b class="text-dark2">💡 Phân tích từng bước:</b> Câu gốc: tuổi thật < tuổi trông có vẻ. Câu mới giữ đúng quan hệ này nhưng đổi động từ chính thành "looks" và tính từ thành "older".</div><div class="mb-2"><b class="text-dark2">📚 Từ vựng cần lưu ý:</b> <b>look + adj</b>: trông có vẻ (dùng adj sau "look", không dùng adv); <b>young</b> /jʌŋ/ ≠ <b>old</b> /oʊld/: trẻ ≠ già</div>`},

{id:7,type:'typing',q:`Rewrite the sentence beginning with the given words, keeping the same meaning.<br><b>He didn't spend as much money as his friends.</b><br>=&gt; His friends ______________________________________.`,vi:`Anh ấy không tiêu nhiều tiền bằng bạn bè của mình.`,answer:`spent more money than he did`,accept:["spent more money than he did","spent more money than him","spent more money than he did.","spent more money than him."],
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: His friends <b>spent more money than he did</b>.</div><div class="ex-card mb-2">He didn't spend as much money as his friends. = His friends spent more money than he did.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Chuyển so sánh bằng phủ định "not as much...as" sang so sánh hơn khẳng định: đảo chủ ngữ, "much" → "more", thêm "than".</div><div class="mb-2"><b class="text-dark2">💡 Phân tích từng bước:</b> Chủ ngữ mới "His friends", động từ khẳng định "spent", "more money", đối tượng còn lại "than he did" (dùng trợ động từ "did" để tránh lặp "spent").</div><div class="mb-2"><b class="text-dark2">✅ Cách diễn đạt khác cũng được chấp nhận:</b> "His friends spent more money than him."</div><div class="mb-2"><b class="text-dark2">📚 Từ vựng cần lưu ý:</b> <b>spend money</b> /spend ˈmʌni/: tiêu tiền (spend–spent–spent); trợ động từ "did" dùng để thay thế cho "spent" ở vế sau, tránh lặp từ</div>`},

{id:8,type:'typing',q:`Rewrite the sentence beginning with the given words, keeping the same meaning.<br><b>I have never met anyone as intelligent as he is.</b><br>=&gt; He is ______________________________________.`,vi:`Tôi chưa từng gặp ai thông minh bằng anh ấy.`,answer:`the most intelligent person I have ever met`,accept:["the most intelligent person i have ever met","the most intelligent person that i have ever met","the most intelligent person i've ever met","the most intelligent person i have ever met.","the most intelligent person that i have ever met.","the most intelligent person i've ever met."],
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: He is <b>the most intelligent person I have ever met</b>.</div><div class="ex-card mb-2">I have never met anyone as intelligent as he is. = He is the most intelligent person I have ever met.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> "Never...anyone as...as" (chưa từng gặp ai bằng) tương đương với so sánh nhất: S + be + the most + adj + N + (that) + S + have ever + Vp2.</div><div class="mb-2"><b class="text-dark2">💡 Phân tích từng bước:</b> Đổi chủ ngữ chính thành "He", tính từ "intelligent" (dài, 4 âm tiết) → "the most intelligent", thêm mệnh đề quan hệ rút gọn "I have ever met".</div><div class="mb-2"><b class="text-dark2">📚 Từ vựng cần lưu ý:</b> <b>intelligent</b> /ɪnˈtelɪdʒənt/ (adj, tính từ dài ≥3 âm tiết): thông minh — so sánh nhất phải dùng "the most intelligent"</div>`},

{id:9,type:'typing',q:`Rewrite the sentence beginning with the given words, keeping the same meaning.<br><b>The Pacific Ocean is the biggest in the world.</b><br>=&gt; The Pacific Ocean ______________________________________.`,vi:`Thái Bình Dương là đại dương lớn nhất thế giới.`,answer:`is bigger than any other ocean in the world`,accept:["is bigger than any other ocean in the world","is bigger than any other ocean in the world."],
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: The Pacific Ocean <b>is bigger than any other ocean in the world</b>.</div><div class="ex-card mb-2">The Pacific Ocean is the biggest in the world. = The Pacific Ocean is bigger than any other ocean in the world.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Chuyển so sánh nhất (the + adj-est) sang so sánh hơn với "any other": S + be + adj-er + than any other + N (số ít).</div><div class="mb-2"><b class="text-dark2">💡 Phân tích từng bước:</b> Giữ nguyên chủ ngữ "The Pacific Ocean", "biggest" → "bigger", thêm "than any other ocean" (danh từ số ít vì "any other" + N số ít) + "in the world".</div><div class="mb-2"><b class="text-dark2">📚 Từ vựng cần lưu ý:</b> <b>ocean</b> /ˈoʊʃn/ (n): đại dương; cấu trúc <b>any other + N (số ít)</b>: bất kỳ... nào khác</div>`},

{id:10,type:'typing',q:`Rewrite the sentence beginning with the given words, keeping the same meaning.<br><b>Diamond is the most valuable of all metals.</b><br>=&gt; No metal ______________________________________.`,vi:`Kim cương là kim loại quý giá nhất trong tất cả các kim loại.`,answer:`is more valuable than diamond`,accept:["is more valuable than diamond","is more valuable than diamond.","is as valuable as diamond","is as valuable as diamond."],
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: No metal <b>is more valuable than diamond</b>.</div><div class="ex-card mb-2">Diamond is the most valuable of all metals. = No metal is more valuable than diamond.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Chuyển so sánh nhất (the most + adj + of all + N) sang so sánh hơn phủ định toàn bộ: No + N (số ít) + be + more + adj + than + N so sánh.</div><div class="mb-2"><b class="text-dark2">💡 Phân tích từng bước:</b> "The most valuable of all metals" = không kim loại nào quý hơn kim cương → "No metal is more valuable than diamond".</div><div class="mb-2"><b class="text-dark2">✅ Cách diễn đạt khác cũng được chấp nhận:</b> "No metal is as valuable as diamond."</div><div class="mb-2"><b class="text-dark2">📚 Từ vựng cần lưu ý:</b> <b>valuable</b> /ˈvæljuəbl/ (adj): quý giá, có giá trị; <b>metal</b> /ˈmetl/ (n): kim loại</div>`},

{id:11,type:'typing',q:`Rewrite the sentence beginning with the given words, keeping the same meaning.<br><b>You read many books. You can get much knowledge.</b><br>=&gt; The more ______________________________________.`,vi:`Bạn đọc càng nhiều sách, bạn càng có được nhiều kiến thức.`,answer:`books you read, the more knowledge you can get`,accept:["books you read, the more knowledge you can get","books you read the more knowledge you can get","books you read, the more knowledge you get","books you read the more knowledge you get","books you read, the more knowledge you can get.","books you read the more knowledge you can get."],
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: The more <b>books you read, the more knowledge you can get</b>.</div><div class="ex-card mb-2">You read many books. You can get much knowledge. = The more books you read, the more knowledge you can get.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Cấu trúc so sánh kép (song song): The more + N/adj + S + V, the more + N/adj + S + V — diễn tả 2 sự việc tăng/giảm cùng lúc.</div><div class="mb-2"><b class="text-dark2">💡 Phân tích từng bước:</b> "Many books" → "the more books", "much knowledge" → "the more knowledge", nối 2 vế bằng dấu phẩy, giữ nguyên chủ ngữ - động từ mỗi vế.</div><div class="mb-2"><b class="text-dark2">✅ Cách diễn đạt khác cũng được chấp nhận:</b> "The more books you read, the more knowledge you get." (bỏ "can" vẫn đúng nghĩa).</div><div class="mb-2"><b class="text-dark2">📚 Từ vựng cần lưu ý:</b> <b>knowledge</b> /ˈnɒlɪdʒ/ (n, không đếm được): kiến thức; cấu trúc song song "The + more..., the + more..." diễn tả 2 điều tăng cùng lúc</div>`},

{id:12,type:'typing',q:`Rewrite the sentence beginning with the given words, keeping the same meaning.<br><b>When he is older, he becomes more thoughtful.</b><br>=&gt; The older ______________________________________.`,vi:`Khi anh ấy càng lớn tuổi, anh ấy càng trở nên chín chắn hơn.`,answer:`he becomes, the more thoughtful he becomes`,accept:["he becomes, the more thoughtful he becomes","he becomes the more thoughtful he becomes","he gets, the more thoughtful he becomes","he gets the more thoughtful he becomes","he is, the more thoughtful he becomes","he is the more thoughtful he becomes","he becomes, the more thoughtful he becomes.","he gets, the more thoughtful he becomes.","he is, the more thoughtful he becomes."],
explain_detail:`<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">✅ Đáp án đúng: The older <b>he becomes, the more thoughtful he becomes</b>.</div><div class="ex-card mb-2">When he is older, he becomes more thoughtful. = The older he becomes, the more thoughtful he becomes.</div><div class="mb-2"><b class="text-dark2">📐 Quy tắc:</b> Cấu trúc so sánh kép: The + so sánh hơn (adj/adv) + S + V, the + so sánh hơn + S + V — diễn tả mối quan hệ tỉ lệ thuận giữa 2 điều.</div><div class="mb-2"><b class="text-dark2">💡 Phân tích từng bước:</b> "When he is older" → "The older he becomes/gets/is", "he becomes more thoughtful" → "the more thoughtful he becomes", nối bằng dấu phẩy.</div><div class="mb-2"><b class="text-dark2">✅ Các cách diễn đạt khác cũng được chấp nhận:</b> "The older he gets, the more thoughtful he becomes." / "The older he is, the more thoughtful he becomes."</div><div class="mb-2"><b class="text-dark2">📚 Từ vựng cần lưu ý:</b> <b>thoughtful</b> /ˈθɔːtfl/ (adj): chín chắn, biết suy nghĩ cho người khác; "become/get/be" đều dùng được trong cấu trúc "the + so sánh hơn"</div>`}
];
